const MODAL_EX1 = [{"id": 1, "type": "fill", "q": "After the training, he will _________operate the new software.", "vi": "Sau khóa đào tạo, anh ấy sẽ có thể vận hành phần mềm mới.", "opts": ["A. can", "B. may", "C. could", "D. be able to"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. be able to</div><div class=\"ex-card mb-2\">After the training, he will <b>be able to</b>_operate the new software.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Sau khóa đào tạo, anh ấy sẽ có thể vận hành phần mềm mới.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 1 — CAN vs BE ABLE TO (khả năng)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. can</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì hai động từ khuyết thiếu không thể đứng liền nhau — không thể nói \"will can\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. may</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì tương tự, \"will may\" không tồn tại — hai modal verb không đứng cạnh nhau.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. could</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"will could\" cũng không tồn tại vì lý do tương tự.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. be able to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Can\" không có dạng tương lai, nên khi cần diễn tả khả năng ở tương lai phải dùng \"will be able to\".</span></div>"}, {"id": 2, "type": "fill", "q": "She will __________ buy a new phone as her current one is not working properly.", "vi": "Cô ấy sẽ phải mua điện thoại mới vì chiếc hiện tại của cô không hoạt động tốt.", "opts": ["A. have to", "B. must", "C. be able to", "D. can"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. have to</div><div class=\"ex-card mb-2\">She will <b>have to</b> buy a new phone as her current one is not working properly.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Cô ấy sẽ phải mua điện thoại mới vì chiếc hiện tại của cô không hoạt động tốt.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 2 — MUST vs HAVE TO (sự cần thiết chủ quan/khách quan)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. have to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Have to\" có dạng tương lai đầy đủ (will have to), diễn tả sự cần thiết khách quan (do điện thoại hỏng, hoàn cảnh bắt buộc) trong tương lai.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must\" không có dạng tương lai — không nói \"will must\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. be able to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì ngữ cảnh nói về sự CẦN THIẾT phải mua điện thoại (do hỏng), không phải khả năng \"có thể mua được\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. can</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can\" không có dạng tương lai — không nói \"will can\".</span></div>"}, {"id": 3, "type": "fill", "q": "I think you ____________apologize for your behavior; it was disrespectful.", "vi": "Tôi nghĩ bạn nên xin lỗi vì hành vi của mình; nó thật thiếu tôn trọng.", "opts": ["A. must", "B. have to", "C. should", "D. ought"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. should</div><div class=\"ex-card mb-2\">I think you <b>should</b>apologize for your behavior; it was disrespectful.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tôi nghĩ bạn nên xin lỗi vì hành vi của mình; nó thật thiếu tôn trọng.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 5 — SHOULD vs OUGHT TO (lời khuyên)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must\" (cần phải, mang tính ép buộc mạnh) không phù hợp với cấu trúc đưa ý kiến nhẹ nhàng \"I think...\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have to\" diễn tả sự bắt buộc khách quan, không phù hợp với việc đưa ra Ý KIẾN cá nhân (\"I think\").</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. should</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"I think + should\" là cấu trúc điển hình để đưa ra lời khuyên/ý kiến nhẹ nhàng, phù hợp ngữ cảnh khuyên ai đó nên xin lỗi.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. ought</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"ought\" phải luôn đi kèm \"to\" (ought to apologize); dùng \"ought\" một mình không đúng ngữ pháp.</span></div>"}, {"id": 4, "type": "fill", "q": "You ______________bring any food to the party; we'll provide everything.", "vi": "Bạn không cần mang đồ ăn gì đến bữa tiệc đâu; chúng tôi sẽ chuẩn bị mọi thứ.", "opts": ["A. don't have to", "B. mustn’t", "C. needn’t", "D. Both A and C are correct"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. Both A and C are correct</div><div class=\"ex-card mb-2\">You <b>Both A and C are correct</b>bring any food to the party; we'll provide everything.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bạn không cần mang đồ ăn gì đến bữa tiệc đâu; chúng tôi sẽ chuẩn bị mọi thứ.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. don't have to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng một phần! \"Don't have to\" (không cần thiết, được phép không làm) diễn tả đúng ý nghĩa của câu — nhưng chưa phải đáp án đầy đủ nhất.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. mustn’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't\" (không được phép — cấm đoán) hoàn toàn khác nghĩa với việc \"không cần mang đồ ăn\" (vẫn được phép mang nếu muốn, chỉ là không bắt buộc).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. needn’t</b><br><span style=\"font-weight:400;font-size:13px\">Đúng một phần! \"Needn't\" cũng diễn tả \"không cần thiết\" tương đương với \"don't have to\" — nhưng chưa phải đáp án đầy đủ nhất.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. Both A and C are correct</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Cả \"don't have to\" và \"needn't\" đều diễn tả sự KHÔNG CẦN THIẾT (được phép không làm), hoàn toàn phù hợp và tương đương nghĩa trong câu này.</span></div>"}, {"id": 5, "type": "fill", "q": "Students ______________use their cell phones during exams. It’s against the rules.", "vi": "Học sinh không được phép sử dụng điện thoại di động trong giờ thi. Điều đó vi phạm quy định.", "opts": ["A. must", "B. mustn't", "C. needn’t", "D. shouldn’t"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. mustn't</div><div class=\"ex-card mb-2\">Students <b>mustn't</b>use their cell phones during exams. It’s against the rules.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Học sinh không được phép sử dụng điện thoại di động trong giờ thi. Điều đó vi phạm quy định.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must\" (phải) mang nghĩa bắt buộc làm, trái ngược hoàn toàn với ý cấm đoán \"against the rules\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. mustn't</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"It's against the rules\" (vi phạm quy định) = một hành vi bị CẤM → mustn't (không được phép).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. needn’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needn't\" (không cần thiết, vẫn được phép làm) không phù hợp với \"against the rules\" (vi phạm quy định, tức là bị CẤM tuyệt đối).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. shouldn’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"shouldn't\" chỉ là lời khuyên không nên làm (mức độ nhẹ), trong khi \"against the rules\" thể hiện sự CẤM ĐOÁN chính thức, mạnh hơn nhiều.</span></div>"}, {"id": 6, "type": "fill", "q": "You ____________go to bed early to get enough rest for tomorrow's exam.", "vi": "Bạn nên đi ngủ sớm để có đủ nghỉ ngơi cho kỳ thi ngày mai.", "opts": ["A. should", "B. must", "C. have to", "D. can"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. should</div><div class=\"ex-card mb-2\">You <b>should</b>go to bed early to get enough rest for tomorrow's exam.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bạn nên đi ngủ sớm để có đủ nghỉ ngơi cho kỳ thi ngày mai.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 5 — SHOULD vs OUGHT TO (lời khuyên)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. should</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Đây là một lời KHUYÊN nhẹ nhàng (nên làm gì để có lợi cho bản thân), phù hợp với \"should\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must\" mang tính ép buộc mạnh, quá nặng nề cho một lời khuyên đơn giản về việc nghỉ ngơi.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have to\" diễn tả sự bắt buộc khách quan (do quy định/hoàn cảnh), không phù hợp với một lời khuyên mang tính cá nhân.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. can</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can\" chỉ khả năng, không phù hợp với ngữ cảnh đưa ra lời khuyên.</span></div>"}, {"id": 7, "type": "fill", "q": "We _______pay our bills by the end of the month or they will cut off the electricity.", "vi": "Chúng ta phải thanh toán hóa đơn trước cuối tháng, nếu không họ sẽ cắt điện.", "opts": ["A. have to", "B. should", "C. may", "D. must"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. must</div><div class=\"ex-card mb-2\">We <b>must</b>_pay our bills by the end of the month or they will cut off the electricity.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Chúng ta phải thanh toán hóa đơn trước cuối tháng, nếu không họ sẽ cắt điện.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 2 — MUST vs HAVE TO (sự cần thiết chủ quan/khách quan)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai — về ngữ pháp \"have to\" cũng có thể dùng, nhưng \"must\" tự nhiên hơn khi nhấn mạnh tính CẤP BÁCH/QUAN TRỌNG của lời cảnh báo hậu quả nghiêm trọng (bị cắt điện) đi kèm ngay sau.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should\" (nên) quá nhẹ so với mức độ nghiêm trọng của hậu quả \"sẽ bị cắt điện\" nếu không thanh toán.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. may</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"may\" (có thể) diễn tả khả năng/sự cho phép, không phù hợp với một NGHĨA VỤ bắt buộc phải thực hiện.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. must</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Must\" nhấn mạnh tính cấp thiết, quan trọng của nghĩa vụ thanh toán, phù hợp với hậu quả nghiêm trọng được cảnh báo ngay sau đó (or...will cut off).</span></div>"}, {"id": 8, "type": "fill", "q": "According to the laws, you ___________ wear a helmet while riding a motorcycle for safety.", "vi": "Theo pháp luật, bạn phải đội mũ bảo hiểm khi đi xe máy để đảm bảo an toàn.", "opts": ["A. must", "B. should", "C. will", "D. have to"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. have to</div><div class=\"ex-card mb-2\">According to the laws, you <b>have to</b>_ wear a helmet while riding a motorcycle for safety.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Theo pháp luật, bạn phải đội mũ bảo hiểm khi đi xe máy để đảm bảo an toàn.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 2 — MUST vs HAVE TO (sự cần thiết chủ quan/khách quan)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must\" diễn tả sự cần thiết mang tính CHỦ QUAN (tự người nói nhận thấy), trong khi \"according to the laws\" (theo pháp luật) là một quy định KHÁCH QUAN từ bên ngoài.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should\" chỉ là lời khuyên, không đủ mạnh để diễn tả một quy định pháp luật bắt buộc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. will</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"will\" diễn tả dự đoán/quyết định tương lai, không phù hợp với việc nêu một quy định pháp luật.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. have to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"According to the laws\" (theo pháp luật) chỉ rõ đây là sự bắt buộc mang tính KHÁCH QUAN từ quy định bên ngoài → have to (đúng theo dấu hiệu phân biệt must/have to).</span></div>"}, {"id": 9, "type": "fill", "q": "He needs ____________ more if he wants to improve his grades.", "vi": "Cậu ấy cần học nhiều hơn nếu muốn cải thiện điểm số.", "opts": ["A. study", "B. to study", "C. studying", "D. to be studied"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. to study</div><div class=\"ex-card mb-2\">He needs <b>to study</b> more if he wants to improve his grades.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Cậu ấy cần học nhiều hơn nếu muốn cải thiện điểm số.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 3 — NEED (động từ thường & động từ khuyết thiếu)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. study</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì khi \"need\" là ĐỘNG TỪ THƯỜNG (chia theo chủ ngữ \"He needs\"), động từ theo sau phải ở dạng \"to V\", không phải V nguyên mẫu.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. to study</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Need\" là động từ thường ở đây (needs, chia theo ngôi thứ 3 số ít) nên động từ theo sau phải là \"to V\": needs to study.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. studying</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"need\" (động từ thường, nghĩa chủ động \"cần làm gì\") không theo sau bởi V-ing; V-ing chỉ dùng khi \"need\" mang nghĩa BỊ ĐỘNG (vd: The car needs washing).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. to be studied</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"to be studied\" (bị động) không đúng nghĩa — \"he\" là người TỰ học, không phải bị ai học.</span></div>"}, {"id": 10, "type": "fill", "q": "She wasn't home when I called her last night; she ___________out.", "vi": "Cô ấy không có nhà khi tôi gọi tối qua; chắc là cô ấy đã đi ra ngoài.", "opts": ["A. should have gone", "B. could have gone", "C. must have gone", "D. can have gone"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. must have gone</div><div class=\"ex-card mb-2\">She wasn't home when I called her last night; she <b>must have gone</b>_out.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Cô ấy không có nhà khi tôi gọi tối qua; chắc là cô ấy đã đi ra ngoài.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. should have gone</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should have gone\" diễn tả một việc LẼ RA phải xảy ra nhưng KHÔNG xảy ra (hối tiếc), không phù hợp với việc suy đoán lý do cô ấy vắng nhà.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. could have gone</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"could have gone\" diễn tả khả năng đã có thể xảy ra nhưng thực tế KHÔNG xảy ra, trái với việc cô ấy THỰC SỰ vắng nhà (bằng chứng rõ ràng).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. must have gone</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Có bằng chứng rõ ràng (cô ấy không có nhà khi gọi) để suy đoán chắc chắn về nguyên nhân trong quá khứ → must have gone (suy đoán logic dựa trên căn cứ thật).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. can have gone</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can have gone\" không phải cấu trúc chuẩn để diễn tả suy đoán khẳng định (thường dùng \"must have\", còn \"can\" phủ định thường dùng ở dạng \"can't have\").</span></div>"}, {"id": 11, "type": "fill", "q": "_________ I call a taxi for you?", "vi": "Để tôi gọi taxi cho bạn nhé?", "opts": ["A. Should", "B. Must", "C. Shall", "D. Will"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. Shall</div><div class=\"ex-card mb-2\"><b>Shall</b>_ I call a taxi for you?</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Để tôi gọi taxi cho bạn nhé?</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 6 — SHALL vs WILL</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. Should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"Should I...?\" thường hỏi xin lời khuyên (Tôi có nên...không?), không phải đề nghị giúp đỡ theo cấu trúc quen thuộc này.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. Must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"Must I...?\" hỏi về sự bắt buộc, không phù hợp với ý đề nghị giúp đỡ.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. Shall</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Cấu trúc \"Shall I...?\" dùng để ĐỀ NGHỊ GIÚP ai đó — Shall I call a taxi for you? (Để tôi gọi taxi cho bạn nhé?).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. Will</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"Will you...?\" mới là cấu trúc đề nghị AI KHÁC giúp MÌNH, không phải mình đề nghị giúp người khác.</span></div>"}, {"id": 12, "type": "fill", "q": "She __________ have listened to her friend's advice; now she's regretting it.", "vi": "Đáng lẽ cô ấy nên nghe theo lời khuyên của bạn mình; giờ cô ấy đang hối hận về điều đó.", "opts": ["A. must", "B. may", "C. might", "D. should"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. should</div><div class=\"ex-card mb-2\">She <b>should</b> have listened to her friend's advice; now she's regretting it.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Đáng lẽ cô ấy nên nghe theo lời khuyên của bạn mình; giờ cô ấy đang hối hận về điều đó.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must have listened\" diễn tả suy đoán chắc chắn RẰNG cô ấy đã nghe lời khuyên, trái với việc cô ấy đang \"hối hận\" (nghĩa là cô ấy đã KHÔNG nghe).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. may</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"may have listened\" diễn tả khả năng không chắc chắn, không phù hợp với ý HỐI TIẾC rõ ràng về một việc đã không xảy ra.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. might</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"might have listened\" tương tự chỉ diễn tả khả năng, không mang ý nghĩa hối tiếc/trách móc như ngữ cảnh yêu cầu.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. should</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Now she's regretting it\" (đang hối hận) cho thấy đây là việc LẼ RA PHẢI làm nhưng đã không làm → should have listened.</span></div>"}, {"id": 13, "type": "fill", "q": "By law, British schools _________ publish their exam results.", "vi": "Theo luật, các trường học ở Anh phải công bố kết quả thi của họ.", "opts": ["A. have to", "B. should", "C. must", "D. can"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. must</div><div class=\"ex-card mb-2\">By law, British schools <b>must</b>_ publish their exam results.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Theo luật, các trường học ở Anh phải công bố kết quả thi của họ.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 2 — MUST vs HAVE TO (sự cần thiết chủ quan/khách quan)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai — về ngữ pháp \"have to\" (khách quan) cũng hợp lý, nhưng trong văn phong trang trọng khi trích dẫn một ĐIỀU LUẬT cụ thể (by law), \"must\" là từ chuẩn mực thường dùng để diễn đạt nghĩa vụ pháp lý một cách dứt khoát.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should\" (nên) chỉ là khuyến nghị, không đủ mạnh để diễn tả một NGHĨA VỤ PHÁP LÝ bắt buộc \"by law\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. must</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Trong văn bản pháp luật/quy định chính thức, \"must\" là từ chuẩn được dùng để tuyên bố nghĩa vụ bắt buộc: \"by law, schools must publish...\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. can</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can\" (có thể) diễn tả khả năng/sự cho phép, hoàn toàn không phù hợp với một NGHĨA VỤ pháp lý bắt buộc.</span></div>"}, {"id": 14, "type": "fill", "q": "She __________to take a break; she's been working all day.", "vi": "Cô ấy nên nghỉ ngơi một chút; cô ấy đã làm việc cả ngày rồi.", "opts": ["A. should", "B. ought", "C. must", "D. have"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. ought</div><div class=\"ex-card mb-2\">She <b>ought</b>to take a break; she's been working all day.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Cô ấy nên nghỉ ngơi một chút; cô ấy đã làm việc cả ngày rồi.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 5 — SHOULD vs OUGHT TO (lời khuyên)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì trong câu đã có sẵn từ \"to\" ngay sau chỗ trống (\"__________to take a break\"); nếu chọn \"should\" sẽ tạo thành \"should to take\" — sai ngữ pháp vì \"should\" không bao giờ đi với \"to\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. ought</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Vì câu đã có sẵn \"to\", chỉ cần thêm \"ought\" để tạo thành cụm chuẩn \"ought to take a break\" — lời khuyên rằng cô ấy xứng đáng được nghỉ ngơi sau một ngày làm việc vất vả.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì tương tự, \"must to take\" cũng sai ngữ pháp — \"must\" không bao giờ đi kèm \"to\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. have</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have to take\" tuy đúng ngữ pháp nhưng mang nghĩa BẮT BUỘC khách quan, không tự nhiên bằng \"ought to\" khi đưa ra một gợi ý tốt cho sức khỏe của cô ấy.</span></div>"}, {"id": 15, "type": "fill", "q": "He ___________ have left; I saw him in the backyard a moment ago.", "vi": "Anh ấy không thể nào đã rời đi được; tôi vừa thấy anh ấy ở sân sau lúc nãy.", "opts": ["A. mustn’t", "B. shouldn’t", "C. needn’t", "D. can’t"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. can’t</div><div class=\"ex-card mb-2\">He <b>can’t</b>_ have left; I saw him in the backyard a moment ago.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Anh ấy không thể nào đã rời đi được; tôi vừa thấy anh ấy ở sân sau lúc nãy.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. mustn’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't have left\" không phải cấu trúc chuẩn để phủ định một suy đoán về quá khứ (mustn't chỉ dùng cho sự cấm đoán ở hiện tại/tương lai).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. shouldn’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"shouldn't have left\" diễn tả một việc LẼ RA không nên xảy ra (nhưng đã xảy ra), không phù hợp với việc PHỦ ĐỊNH khả năng anh ta đã rời đi.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. needn’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needn't have left\" diễn tả một việc không cần thiết đã làm, không phù hợp với ý nghĩa phủ định sự việc dựa trên bằng chứng ở đây.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. can’t</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Có bằng chứng rõ ràng (vừa nhìn thấy anh ta ở sân sau) để PHỦ ĐỊNH khả năng anh ta đã rời đi → can't have left (không thể nào đã...).</span></div>"}, {"id": 16, "type": "fill", "q": "He ___________ have rushed to catch the train; it was delayed by half an hour.", "vi": "Anh ấy lẽ ra không cần vội vàng bắt tàu; chuyến tàu đã bị hoãn nửa tiếng.", "opts": ["A. can’t", "B. mustn’t", "C. needn’t", "D. mightn’t"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. needn’t</div><div class=\"ex-card mb-2\">He <b>needn’t</b>_ have rushed to catch the train; it was delayed by half an hour.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Anh ấy lẽ ra không cần vội vàng bắt tàu; chuyến tàu đã bị hoãn nửa tiếng.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. can’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can't have rushed\" diễn tả sự phủ định một sự việc đã xảy ra (không thể đã xảy ra), trái với thực tế anh ta ĐÃ vội vàng.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. mustn’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't have rushed\" không phải cấu trúc chuẩn của modal perfect.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. needn’t</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Việc vội vàng là THỪA vì tàu bị hoãn (không cần thiết nhưng đã làm rồi) → needn't have rushed.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. mightn’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mightn't have rushed\" diễn tả khả năng không chắc chắn, không phù hợp với việc khẳng định rõ ràng rằng việc vội vàng là KHÔNG CẦN THIẾT (do biết chắc tàu bị hoãn).</span></div>"}, {"id": 17, "type": "fill", "q": "I guess he ___________ have left his phone at home; he hasn't answered any calls.", "vi": "Tôi đoán có lẽ anh ấy đã để quên điện thoại ở nhà; anh ấy không trả lời bất kỳ cuộc gọi nào.", "opts": ["A. may", "B. must", "C. should", "D. could"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. may</div><div class=\"ex-card mb-2\">I guess he <b>may</b>_ have left his phone at home; he hasn't answered any calls.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tôi đoán có lẽ anh ấy đã để quên điện thoại ở nhà; anh ấy không trả lời bất kỳ cuộc gọi nào.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. may</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"I guess\" (tôi đoán) cho thấy đây là một suy đoán KHÔNG CHẮC CHẮN, phù hợp với \"may have left\" (có thể đã...).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must have left\" diễn tả sự suy đoán CHẮC CHẮN dựa trên căn cứ vững chắc, không khớp với thái độ không chắc chắn thể hiện qua từ \"guess\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should have left\" diễn tả một việc LẼ RA đã phải xảy ra (hối tiếc), không phù hợp với việc đơn thuần suy đoán nguyên nhân.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. could</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"could have left\" thường ngụ ý khả năng đã xảy ra nhưng thực tế KHÔNG xảy ra, không phù hợp bằng \"may\" khi chỉ đơn thuần đưa ra một khả năng có thể đúng.</span></div>"}, {"id": 18, "type": "fill", "q": "I _________ have helped you with the cooking; you didn't need to do it all yourself.", "vi": "Đáng lẽ tôi nên giúp bạn nấu ăn; bạn không cần phải tự làm hết mọi thứ một mình.", "opts": ["A. must", "B. should", "C. can", "D. could"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. should</div><div class=\"ex-card mb-2\">I <b>should</b>_ have helped you with the cooking; you didn't need to do it all yourself.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Đáng lẽ tôi nên giúp bạn nấu ăn; bạn không cần phải tự làm hết mọi thứ một mình.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must have helped\" là suy đoán chắc chắn về một sự việc đã xảy ra, không phù hợp với ngữ cảnh HỐI TIẾC vì đã không giúp.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. should</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Đây là sự hối tiếc về việc LẼ RA nên làm (giúp nấu ăn) nhưng đã không làm → should have helped.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. can</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can have helped\" không phải là cấu trúc modal perfect chuẩn để diễn tả sự hối tiếc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. could</b><br><span style=\"font-weight:400;font-size:13px\">Sai — \"could have helped\" ngụ ý có khả năng đã giúp nhưng KHÔNG giúp (nhấn mạnh khả năng), trong khi \"should have helped\" nhấn mạnh đúng hơn về NGHĨA VỤ/mong muốn lẽ ra nên làm, phù hợp hơn với thái độ tự trách trong câu.</span></div>"}, {"id": 19, "type": "fill", "q": "The roof needs ___________before the rainy season.", "vi": "Mái nhà cần được sửa chữa trước mùa mưa.", "opts": ["A. repair", "B. be repaired", "C. repairing", "D. to repair"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. repairing</div><div class=\"ex-card mb-2\">The roof needs <b>repairing</b>_before the rainy season.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Mái nhà cần được sửa chữa trước mùa mưa.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 3 — NEED (động từ thường & động từ khuyết thiếu)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. repair</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needs\" (động từ thường) cần \"to V\" hoặc \"V-ing\" theo sau, không dùng V nguyên mẫu trực tiếp.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. be repaired</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"needs be repaired\" thiếu \"to\" — nếu dùng dạng bị động phải là \"needs TO BE repaired\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. repairing</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Cái mái nhà\" là vật CẦN ĐƯỢC sửa (mang nghĩa bị động) → dùng \"need + V-ing\": needs repairing (= needs to be repaired).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. to repair</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"to repair\" mang nghĩa chủ động (mái nhà tự đi sửa), không đúng — cần nghĩa bị động vì mái nhà là vật ĐƯỢC sửa.</span></div>"}, {"id": 20, "type": "fill", "q": "She _______ play the piano beautifully when she was younger.", "vi": "Cô ấy có thể chơi piano rất hay khi còn trẻ.", "opts": ["A. can", "B. was able", "C. could", "D. might"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. could</div><div class=\"ex-card mb-2\">She <b>could</b>_ play the piano beautifully when she was younger.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Cô ấy có thể chơi piano rất hay khi còn trẻ.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 8 — CAN vs COULD</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. can</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can\" chỉ dùng cho hiện tại/tương lai, không phù hợp với mốc thời gian quá khứ \"when she was younger\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. was able</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"to\" — phải là \"was able TO play\", không phải \"was able play\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. could</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Đây là khả năng CHUNG CHUNG trong quá khứ (biết chơi piano hay khi còn trẻ, không phải một lần cụ thể) → could (phù hợp với quy tắc CAN/COULD).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. might</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"might\" diễn tả khả năng không chắc chắn, không phù hợp với việc khẳng định về khả năng chơi đàn của cô ấy.</span></div>"}, {"id": 21, "type": "fill", "q": "You are not allowed to take photos in the museum.", "vi": "Bạn không được phép chụp ảnh trong bảo tàng.", "opts": ["A. You may take photos in the museum.", "B. You should take photos in the museum.", "C. You mustn’t take photos in the museum.", "D. You needn’t take photos in the museum."], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. You mustn’t take photos in the museum.</div><div class=\"ex-card mb-2\">You are not allowed to take photos in the museum.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bạn không được phép chụp ảnh trong bảo tàng.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. You may take photos in the museum.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"may\" (được phép) mang nghĩa ngược lại hoàn toàn với câu gốc \"not allowed\" (không được phép).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. You should take photos in the museum.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should\" (nên) là lời khuyên, không diễn tả đúng ý CẤM ĐOÁN của câu gốc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. You mustn’t take photos in the museum.</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Not allowed to\" (không được phép) tương đương với \"mustn't\" (bị cấm) — cùng diễn tả sự CẤM ĐOÁN.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. You needn’t take photos in the museum.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needn't\" (không cần thiết nhưng vẫn được phép) khác hoàn toàn với \"not allowed\" (bị cấm tuyệt đối, không được phép dù muốn).</span></div>"}, {"id": 22, "type": "fill", "q": "I thought it was not necessary to book tickets for the film in advance, but I was wrong.", "vi": "Tôi cứ nghĩ là không cần đặt vé xem phim trước, nhưng tôi đã sai.", "opts": ["A. I needn’t have booked tickets for the film in advance.", "B. I couldn’t have booked tickets for the film in advance.", "C. I should have booked tickets for the film in advance.", "D. I must have booked tickets for the film in advance."], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. I should have booked tickets for the film in advance.</div><div class=\"ex-card mb-2\">I thought it was not necessary to book tickets for the film in advance, but I was wrong.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tôi cứ nghĩ là không cần đặt vé xem phim trước, nhưng tôi đã sai.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. I needn’t have booked tickets for the film in advance.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needn't have booked\" diễn tả việc đặt vé là KHÔNG CẦN THIẾT — trái ngược với ý nghĩa câu gốc (thực ra việc đặt vé trước LÀ cần thiết, vì người nói \"đã sai\" khi nghĩ không cần).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. I couldn’t have booked tickets for the film in advance.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"couldn't have booked\" (không thể đã đặt vé) không liên quan đến ý nghĩa cần thiết/không cần thiết của câu gốc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. I should have booked tickets for the film in advance.</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Vì nghĩ sai rằng không cần đặt vé trước (nhưng thực ra là cần) → thể hiện sự hối tiếc do đã không đặt vé trước khi lẽ ra nên làm: should have booked.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. I must have booked tickets for the film in advance.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must have booked\" là suy đoán rằng việc đặt vé CHẮC CHẮN đã xảy ra, không phù hợp với ngữ cảnh hối tiếc về việc đã không làm.</span></div>"}, {"id": 23, "type": "fill", "q": "I’m sure that they had practiced hard for the games as they won a lot of medals.", "vi": "Tôi chắc chắn rằng họ đã luyện tập chăm chỉ cho cuộc thi vì họ đã giành được rất nhiều huy chương.", "opts": ["A. They couldn’t have practiced hard for the games as they won a lot of medals", "B. They must have practiced hard for the games as they won a lot of medals", "C. They shouldn’t have practiced hard for the games as they won a lot of medals", "D. They might have practiced hard for the games as they won a lot of medals."], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. They must have practiced hard for the games as they won a lot of medals</div><div class=\"ex-card mb-2\">I’m sure that they had practiced hard for the games as they won a lot of medals.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tôi chắc chắn rằng họ đã luyện tập chăm chỉ cho cuộc thi vì họ đã giành được rất nhiều huy chương.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. They couldn’t have practiced hard for the games as they won a lot of medals</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"couldn't have practiced\" (không thể đã luyện tập) mang nghĩa phủ định, trái ngược hoàn toàn với sự CHẮC CHẮN (\"I'm sure\") trong câu gốc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. They must have practiced hard for the games as they won a lot of medals</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"I'm sure\" (tôi chắc chắn) + căn cứ rõ ràng (giành nhiều huy chương) → suy đoán chắc chắn về quá khứ: must have practiced.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. They shouldn’t have practiced hard for the games as they won a lot of medals</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"shouldn't have practiced\" diễn tả một việc LẼ RA không nên làm, hoàn toàn không phù hợp với ngữ cảnh khen ngợi thành tích.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. They might have practiced hard for the games as they won a lot of medals.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"might have practiced\" chỉ diễn tả khả năng không chắc chắn, không khớp với thái độ CHẮC CHẮN (\"I'm sure\") của người nói.</span></div>"}, {"id": 24, "type": "fill", "q": "It was wrong of you to criticise your son in front of his friends.", "vi": "Bạn đã sai khi chỉ trích con trai mình trước mặt bạn bè của nó.", "opts": ["A. You could have criticised your son in front of his friends.", "B. You must have criticised your son in front of his friends.", "C. You mightn’t have criticised your son in front of his friends.", "D. You shouldn’t have criticised your son in front of his friends."], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. You shouldn’t have criticised your son in front of his friends.</div><div class=\"ex-card mb-2\">It was wrong of you to criticise your son in front of his friends.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bạn đã sai khi chỉ trích con trai mình trước mặt bạn bè của nó.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. You could have criticised your son in front of his friends.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"could have criticised\" chỉ nêu khả năng đã có thể làm, không mang ý PHÊ PHÁN hành động sai trái như câu gốc yêu cầu.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. You must have criticised your son in front of his friends.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must have criticised\" là suy đoán về việc đã xảy ra, không mang ý nghĩa phê phán \"đó là điều sai trái\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. You mightn’t have criticised your son in front of his friends.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mightn't have criticised\" chỉ diễn tả khả năng không chắc chắn, không phù hợp với ý khẳng định chắc chắn rằng hành động đó là SAI.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. You shouldn’t have criticised your son in front of his friends.</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"It was wrong of you to do sth\" (bạn đã sai khi làm gì) tương đương với việc PHÊ PHÁN một hành động LẼ RA không nên làm nhưng đã làm → shouldn't have criticised.</span></div>"}, {"id": 25, "type": "fill", "q": "Sally paid for her travel in advance, but it wasn’t necessary.", "vi": "Sally đã thanh toán tiền du lịch trước, nhưng điều đó là không cần thiết.", "opts": ["A. Sally needn't have paid for her travel in advance.", "B. Sally might not have paid for her travel in advance.", "C. Sally may not have paid for her travel in advance.", "D. Sally couldn’t have paid for her travel in advance."], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. Sally needn't have paid for her travel in advance.</div><div class=\"ex-card mb-2\">Sally paid for her travel in advance, but it wasn’t necessary.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Sally đã thanh toán tiền du lịch trước, nhưng điều đó là không cần thiết.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. Sally needn't have paid for her travel in advance.</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Sally ĐÃ thanh toán trước (một việc thừa, không cần thiết) → needn't have paid (lẽ ra không cần thiết phải làm nhưng đã làm).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. Sally might not have paid for her travel in advance.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"might not have paid\" gợi ý rằng có thể Sally đã KHÔNG thanh toán, trái với sự thật là cô ấy ĐÃ thanh toán rồi.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. Sally may not have paid for her travel in advance.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì tương tự, \"may not have paid\" cũng gợi ý khả năng cô ấy không thanh toán, sai với sự thật đã nêu trong câu gốc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. Sally couldn’t have paid for her travel in advance.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"couldn't have paid\" (không thể đã thanh toán) phủ định hoàn toàn sự việc, trái với thực tế Sally ĐÃ thanh toán.</span></div>"}, {"id": 26, "type": "fill", "q": "Perhaps he will return before you call.", "vi": "Có lẽ anh ấy sẽ trở về trước khi bạn gọi.", "opts": ["A. He may be returning before you called.", "B. He may/might have returned before you called.", "C. He should have returned before you called.", "D. He may return before you call."], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. He may return before you call.</div><div class=\"ex-card mb-2\">Perhaps he will return before you call.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Có lẽ anh ấy sẽ trở về trước khi bạn gọi.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 7 — MAY vs MIGHT (có lẽ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. He may be returning before you called.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"before you called\" (quá khứ) không khớp với ý nghĩa TƯƠNG LAI của câu gốc (\"Perhaps he WILL return\").</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. He may/might have returned before you called.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"may have returned\" (modal perfect) chỉ dùng để suy đoán về QUÁ KHỨ, trong khi câu gốc nói về một sự việc ở TƯƠNG LAI.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. He should have returned before you called.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should have returned\" mang ý nghĩa hối tiếc về quá khứ, hoàn toàn khác với ý nghĩa \"có lẽ, có thể\" ở tương lai của câu gốc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. He may return before you call.</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Perhaps + tương lai\" tương đương với \"may + V nguyên mẫu\" để diễn tả khả năng có thể xảy ra ở tương lai: he may return before you call.</span></div>"}, {"id": 27, "type": "fill", "q": "It is possible that he will redecorate his house this year.", "vi": "Có khả năng là anh ấy sẽ trang trí lại nhà mình trong năm nay.", "opts": ["A. He might redecorate his house this year.", "B. He can't redecorate his house this year.", "C. He must redecorate his house this year.", "D. He won't redecorate his house this year."], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. He might redecorate his house this year.</div><div class=\"ex-card mb-2\">It is possible that he will redecorate his house this year.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Có khả năng là anh ấy sẽ trang trí lại nhà mình trong năm nay.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 7 — MAY vs MIGHT (có lẽ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. He might redecorate his house this year.</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"It is possible that...will...\" (có khả năng rằng sẽ...) tương đương với \"might/may + V\" diễn tả khả năng có thể xảy ra ở tương lai.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. He can't redecorate his house this year.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can't\" (không thể) mang nghĩa phủ định hoàn toàn, trái ngược với ý \"có khả năng\" của câu gốc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. He must redecorate his house this year.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must\" (chắc chắn phải) diễn tả sự chắc chắn/bắt buộc, mạnh hơn nhiều so với \"có khả năng\" (possible) trong câu gốc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. He won't redecorate his house this year.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"won't\" (sẽ không) hoàn toàn trái ngược với ý nghĩa \"có khả năng sẽ\" của câu gốc.</span></div>"}, {"id": 28, "type": "fill", "q": "It's not necessary for you to call a taxi; I'll drive you home.", "vi": "Bạn không cần gọi taxi đâu; tôi sẽ chở bạn về nhà.", "opts": ["A. You shouldn’t call a taxi but I'll drive you home.", "B. You needn’t call a taxi as I'll drive you home.", "C. You can’t call a taxi so I'll drive you home.", "D. You mustn’t call a taxi because I'll drive you home."], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. You needn’t call a taxi as I'll drive you home.</div><div class=\"ex-card mb-2\">It's not necessary for you to call a taxi; I'll drive you home.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bạn không cần gọi taxi đâu; tôi sẽ chở bạn về nhà.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. You shouldn’t call a taxi but I'll drive you home.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"shouldn't\" (không nên) là lời khuyên phản đối, không đúng với ý nghĩa \"không cần thiết\" (vẫn được phép nếu muốn) của câu gốc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. You needn’t call a taxi as I'll drive you home.</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Not necessary\" (không cần thiết) tương đương với \"needn't\" (không cần) — cùng ý nghĩa không bắt buộc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. You can’t call a taxi so I'll drive you home.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can't\" (không thể) diễn tả sự bất khả/cấm đoán, khác hoàn toàn với ý \"không cần thiết\" của câu gốc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. You mustn’t call a taxi because I'll drive you home.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't\" (không được phép — cấm đoán) mang nghĩa hoàn toàn khác với \"not necessary\" (không cần thiết, nhưng vẫn được phép nếu muốn).</span></div>"}, {"id": 29, "type": "fill", "q": "I'm sure she didn't forget my birthday; she always remembers important dates.", "vi": "Tôi chắc chắn cô ấy không quên sinh nhật tôi; cô ấy luôn nhớ những ngày quan trọng.", "opts": ["A. She can't have forgotten my birthday as she always remembers important dates.", "B. She needn’t have forgotten my birthday for she always remembers important dates.", "C. She shouldn’t have forgotten my birthday because she always remembers important dates.", "D. She can't forget my birthday now that she always remembers important dates."], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. She can't have forgotten my birthday as she always remembers important dates.</div><div class=\"ex-card mb-2\">I'm sure she didn't forget my birthday; she always remembers important dates.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tôi chắc chắn cô ấy không quên sinh nhật tôi; cô ấy luôn nhớ những ngày quan trọng.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. She can't have forgotten my birthday as she always remembers important dates.</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"I'm sure...didn't\" (chắc chắn không) + căn cứ vững chắc → suy đoán phủ định chắc chắn về quá khứ: can't have forgotten (không thể đã quên).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. She needn’t have forgotten my birthday for she always remembers important dates.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needn't have forgotten\" không diễn tả ý PHỦ ĐỊNH chắc chắn một sự việc, mà nói về việc không cần thiết đã làm.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. She shouldn’t have forgotten my birthday because she always remembers important dates.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"shouldn't have forgotten\" mang ý PHÊ PHÁN việc đã quên (giả định rằng cô ấy ĐÃ quên), trái với ý câu gốc là cô ấy KHÔNG quên.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. She can't forget my birthday now that she always remembers important dates.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can't forget\" (hiện tại/tương lai) không phù hợp — câu gốc nói về QUÁ KHỨ (\"didn't forget my birthday\" - đã xảy ra rồi, cần modal perfect).</span></div>"}, {"id": 30, "type": "fill", "q": "It is necessary for your grandfather to exercise regularly to recover quickly.", "vi": "Ông của bạn cần tập thể dục thường xuyên để hồi phục nhanh.", "opts": ["A. Your grandfather need to exercise regularly to recover quickly.", "B. Your grandfather needs to exercise regularly to recover quickly.", "C. Your grandfather needs exercise regularly to recover quickly.", "D. Your grandfather needs exercising regularly to recover quickly."], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. Your grandfather needs to exercise regularly to recover quickly.</div><div class=\"ex-card mb-2\">It is necessary for your grandfather to exercise regularly to recover quickly.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Ông của bạn cần tập thể dục thường xuyên để hồi phục nhanh.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 3 — NEED (động từ thường & động từ khuyết thiếu)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. Your grandfather need to exercise regularly to recover quickly.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số ít \"your grandfather\" (ngôi thứ ba số ít) cần động từ thường chia \"needs\", không phải \"need\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. Your grandfather needs to exercise regularly to recover quickly.</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Need\" là ĐỘNG TỪ THƯỜNG ở đây (mang nghĩa chủ động — ông cần tự làm gì), chia theo chủ ngữ số ít \"needs\", theo sau là \"to V\": needs to exercise.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. Your grandfather needs exercise regularly to recover quickly.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"to\" trước \"exercise\" — động từ thường \"needs\" luôn cần \"to V\" theo sau.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. Your grandfather needs exercising regularly to recover quickly.</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needs exercising\" (V-ing) chỉ dùng khi \"need\" mang nghĩa BỊ ĐỘNG (vật cần được làm gì), không phù hợp ở đây vì ông là người TỰ tập thể dục (chủ động).</span></div>"}];
const MODAL_EX2 = [{"id": 1, "type": "fill", "q": "All students__________wear uniforms at school because it is a rule.", "vi": "Tất cả học sinh phải mặc đồng phục ở trường vì đó là quy định.", "opts": ["A. should", "B. have to", "C. ought to", "D. must"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. have to</div><div class=\"ex-card mb-2\">All students<b>have to</b>wear uniforms at school because it is a rule.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tất cả học sinh phải mặc đồng phục ở trường vì đó là quy định.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 2 — MUST vs HAVE TO (sự cần thiết chủ quan/khách quan)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should\" (nên) chỉ là lời khuyên, không đủ mạnh để diễn tả một QUY ĐỊNH bắt buộc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. have to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Because it is a rule\" (vì đó là quy định) chỉ rõ đây là sự bắt buộc mang tính KHÁCH QUAN từ nội quy nhà trường → have to.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. ought to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"ought to\" (nên, mức độ trung bình) không đủ mạnh và không đúng bản chất khách quan của một QUY ĐỊNH.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must\" diễn tả sự cần thiết CHỦ QUAN (tự nhận thức), trong khi \"because it is a rule\" nhấn mạnh đây là quy định KHÁCH QUAN từ nhà trường, nên \"have to\" phù hợp hơn.</span></div>"}, {"id": 2, "type": "fill", "q": "This drink isn't beneficial for health. You__________drink it too much.", "vi": "Thức uống này không tốt cho sức khỏe. Bạn không nên uống nó quá nhiều.", "opts": ["A. should", "B. ought to not", "C. ought not to", "D. mustn't"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. ought not to</div><div class=\"ex-card mb-2\">This drink isn't beneficial for health. You<b>ought not to</b>drink it too much.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Thức uống này không tốt cho sức khỏe. Bạn không nên uống nó quá nhiều.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 5 — SHOULD vs OUGHT TO (lời khuyên)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"not\" — \"should\" đơn thuần mang nghĩa khẳng định, không diễn tả được lời khuyên PHẢN ĐỐI (không nên) trong câu.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. ought to not</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì trật tự từ sai — phủ định của \"ought to\" phải là \"ought NOT to\", không phải \"ought to NOT\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. ought not to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Phủ định đúng ngữ pháp của \"ought to\" là \"ought not to\" — lời khuyên không nên uống quá nhiều, phù hợp mức độ một lời khuyên về sức khỏe.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. mustn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't\" (bị cấm hoàn toàn) quá mạnh so với ngữ cảnh chỉ là một LỜI KHUYÊN về sức khỏe, không phải lệnh cấm tuyệt đối.</span></div>"}, {"id": 3, "type": "fill", "q": "This warning sign indicates that you__________step on the grass.", "vi": "Biển cảnh báo này cho biết bạn không được phép giẫm lên cỏ.", "opts": ["A. shouldn't", "B. mustn't", "C. don't have to", "D. ought not to"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. mustn't</div><div class=\"ex-card mb-2\">This warning sign indicates that you<b>mustn't</b>step on the grass.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Biển cảnh báo này cho biết bạn không được phép giẫm lên cỏ.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. shouldn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"shouldn't\" chỉ là lời khuyên nhẹ, không đủ mạnh để diễn tả một BIỂN CẤM chính thức.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. mustn't</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Warning sign\" (biển cảnh báo/cấm) diễn tả sự CẤM ĐOÁN chính thức → mustn't (không được phép).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. don't have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"don't have to\" (không cần thiết, vẫn được phép) hoàn toàn khác nghĩa với một BIỂN CẤM (bị cấm tuyệt đối).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. ought not to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"ought not to\" cũng chỉ là lời khuyên (mức trung bình), không đủ mạnh để diễn tả sự cấm đoán chính thức từ biển báo.</span></div>"}, {"id": 4, "type": "fill", "q": "I think you_______do exercise regularly in order to keep your body in good shape.", "vi": "Tôi nghĩ bạn nên tập thể dục thường xuyên để giữ cho cơ thể khỏe mạnh.", "opts": ["A. must", "B. should", "C. ought to", "D. Both B and C are correct"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. Both B and C are correct</div><div class=\"ex-card mb-2\">I think you<b>Both B and C are correct</b>_do exercise regularly in order to keep your body in good shape.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tôi nghĩ bạn nên tập thể dục thường xuyên để giữ cho cơ thể khỏe mạnh.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 5 — SHOULD vs OUGHT TO (lời khuyên)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must\" (bắt buộc mạnh, mang tính chủ quan gay gắt) không phù hợp với cấu trúc đưa ý kiến nhẹ nhàng \"I think...\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. should</b><br><span style=\"font-weight:400;font-size:13px\">Đúng một phần! \"Should\" là lời khuyên phù hợp với \"I think\" — nhưng chưa phải đáp án đầy đủ nhất.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. ought to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng một phần! \"Ought to\" cũng là lời khuyên có ý nghĩa tương đương \"should\" trong ngữ cảnh này — nhưng chưa phải đáp án đầy đủ nhất.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. Both B and C are correct</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Cả \"should\" và \"ought to\" đều là những lời khuyên hợp lý và có thể dùng thay thế nhau trong ngữ cảnh này, nên \"Both B and C\" là đáp án đúng nhất.</span></div>"}, {"id": 5, "type": "fill", "q": "I will lend you some money, but you_________pay it back to me next week.", "vi": "Tôi sẽ cho bạn mượn tiền, nhưng bạn phải trả lại cho tôi vào tuần sau.", "opts": ["A. should", "B. have to", "C. must", "D. mustn't"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. must</div><div class=\"ex-card mb-2\">I will lend you some money, but you<b>must</b>_pay it back to me next week.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tôi sẽ cho bạn mượn tiền, nhưng bạn phải trả lại cho tôi vào tuần sau.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 2 — MUST vs HAVE TO (sự cần thiết chủ quan/khách quan)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should\" (nên) quá nhẹ, không thể hiện được điều kiện RÀNG BUỘC bắt buộc mà người nói đặt ra khi cho mượn tiền.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai — về ngữ pháp \"have to\" cũng khả thi, nhưng \"must\" tự nhiên hơn ở đây vì đây là yêu cầu CHỦ QUAN, cá nhân của chính người nói (điều kiện họ tự đặt ra khi cho mượn tiền), không phải quy định khách quan từ bên ngoài.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. must</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Đây là yêu cầu mang tính CHỦ QUAN của chính người nói (điều kiện cho mượn tiền do họ tự đặt ra) → must, phù hợp với quy tắc must=chủ quan.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. mustn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't\" (không được phép) mang nghĩa cấm đoán, hoàn toàn trái với ý nghĩa BẮT BUỘC phải trả tiền của câu gốc.</span></div>"}, {"id": 6, "type": "fill", "q": "Hoa__________feed the cats because her mother has done it already.", "vi": "Hoa không cần cho mèo ăn nữa vì mẹ cô ấy đã làm việc đó rồi.", "opts": ["A. has to", "B. doesn't have to", "C. must", "D. Both A and C are correct"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. doesn't have to</div><div class=\"ex-card mb-2\">Hoa<b>doesn't have to</b>feed the cats because her mother has done it already.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Hoa không cần cho mèo ăn nữa vì mẹ cô ấy đã làm việc đó rồi.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. has to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has to\" (phải làm) trái ngược với ý nghĩa câu: mẹ đã làm rồi nên Hoa KHÔNG CẦN làm nữa.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. doesn't have to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Her mother has done it already\" (mẹ đã làm rồi) cho thấy việc cho mèo ăn không còn cần thiết đối với Hoa → doesn't have to (không cần thiết).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must\" (phải làm) cũng trái với ý nghĩa không cần thiết của câu.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. Both A and C are correct</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cả A và C đều mang nghĩa BẮT BUỘC PHẢI làm, trái ngược hoàn toàn với ý nghĩa \"không cần thiết\" của câu gốc.</span></div>"}, {"id": 7, "type": "fill", "q": "Those audiences__________show their tickets before entering the concert hall.", "vi": "Những khán giả đó phải xuất trình vé trước khi vào phòng hòa nhạc.", "opts": ["A. have to", "B. must", "C. ought to", "D. don't have to"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. have to</div><div class=\"ex-card mb-2\">Those audiences<b>have to</b>show their tickets before entering the concert hall.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Những khán giả đó phải xuất trình vé trước khi vào phòng hòa nhạc.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 2 — MUST vs HAVE TO (sự cần thiết chủ quan/khách quan)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. have to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Đây là quy định chung của địa điểm tổ chức (khách quan, không phải ý kiến cá nhân của khán giả) → have to.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai — về ngữ pháp \"must\" vẫn khả thi, nhưng vì đây là yêu cầu từ BÊN NGOÀI (quy định của địa điểm tổ chức sự kiện), \"have to\" phù hợp hơn với bản chất khách quan của yêu cầu này.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. ought to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"ought to\" chỉ là lời khuyên (mức trung bình), không đủ mạnh để diễn tả một YÊU CẦU bắt buộc từ ban tổ chức.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. don't have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"don't have to\" (không cần thiết) trái ngược hoàn toàn với việc BẮT BUỘC phải xuất trình vé để được vào.</span></div>"}, {"id": 8, "type": "fill", "q": "The children__________spend too much time playing computer games.", "vi": "Bọn trẻ không nên dành quá nhiều thời gian chơi game trên máy tính.", "opts": ["A. mustn't", "B. ought to not", "C. shouldn't", "D. Both B and C are correct"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. shouldn't</div><div class=\"ex-card mb-2\">The children<b>shouldn't</b>spend too much time playing computer games.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bọn trẻ không nên dành quá nhiều thời gian chơi game trên máy tính.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 5 — SHOULD vs OUGHT TO (lời khuyên)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. mustn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't\" (bị cấm tuyệt đối) quá mạnh so với ngữ cảnh chỉ là một lời khuyên của phụ huynh, không phải lệnh cấm chính thức.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. ought to not</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì trật tự từ sai — phủ định của \"ought to\" phải là \"ought NOT to\", không phải \"ought to NOT\", nên đáp án này về ngữ pháp không chính xác.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. shouldn't</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Shouldn't\" (không nên) là lời khuyên phù hợp mức độ với ngữ cảnh khuyên trẻ em không nên chơi game quá nhiều.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. Both B and C are correct</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đáp án B (\"ought to not\") sai về mặt ngữ pháp (trật tự từ), nên \"Both B and C\" không thể là đáp án đúng.</span></div>"}, {"id": 9, "type": "fill", "q": "In case you’ve suffered from an injury, you____________see the doctor today.", "vi": "Trong trường hợp bạn bị thương, bạn nên đi khám bác sĩ ngay hôm nay.", "opts": ["A. had better", "B. must", "C. ought", "D. have better"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. had better</div><div class=\"ex-card mb-2\">In case you’ve suffered from an injury, you<b>had better</b>see the doctor today.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Trong trường hợp bạn bị thương, bạn nên đi khám bác sĩ ngay hôm nay.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 5 — SHOULD vs OUGHT TO (lời khuyên)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. had better</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Had better + V(bare)\" diễn tả một lời khuyên MẠNH, khẩn cấp (nên làm ngay, nếu không sẽ có hậu quả xấu) — rất phù hợp với tình huống bị thương cần đi khám ngay.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must\" (bắt buộc) quá cứng nhắc so với một lời khuyên khẩn cấp mang tính quan tâm, chăm sóc sức khỏe.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. ought</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"ought\" phải luôn đi kèm \"to\" (ought to see), dùng một mình không đúng ngữ pháp.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. have better</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have better\" không phải là cụm từ tồn tại trong tiếng Anh (nhầm với \"had better\").</span></div>"}, {"id": 10, "type": "fill", "q": "Water park is free for kids under 6 years old, so you__________pay money for your son.", "vi": "Công viên nước miễn phí cho trẻ em dưới 6 tuổi, vì vậy bạn không cần trả tiền cho con trai mình.", "opts": ["A. have to", "B. mustn't", "C. should", "D. don't have to"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. don't have to</div><div class=\"ex-card mb-2\">Water park is free for kids under 6 years old, so you<b>don't have to</b>pay money for your son.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Công viên nước miễn phí cho trẻ em dưới 6 tuổi, vì vậy bạn không cần trả tiền cho con trai mình.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have to\" (phải trả tiền) trái ngược với thông tin \"miễn phí cho trẻ dưới 6 tuổi\" đã nêu.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. mustn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't\" (không được phép trả tiền — cấm đoán) không đúng nghĩa; đây chỉ đơn giản là KHÔNG CẦN trả tiền, không phải bị cấm trả.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should\" (nên) không phù hợp — đây là một THỰC TẾ khách quan (miễn phí) chứ không phải một lời khuyên.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. don't have to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Free for kids under 6\" (miễn phí) → không cần thiết phải trả tiền: don't have to.</span></div>"}, {"id": 11, "type": "fill", "q": "My car broke down yesterday, so I__________catch a taxi to the office.", "vi": "Xe của tôi bị hỏng hôm qua, vì vậy tôi đã phải bắt taxi đến văn phòng.", "opts": ["A. have to", "B. had better", "C. had to", "D. has to"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. had to</div><div class=\"ex-card mb-2\">My car broke down yesterday, so I<b>had to</b>catch a taxi to the office.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Xe của tôi bị hỏng hôm qua, vì vậy tôi đã phải bắt taxi đến văn phòng.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 2 — MUST vs HAVE TO (sự cần thiết chủ quan/khách quan)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have to\" (hiện tại) không khớp thì với \"broke down yesterday\" (quá khứ).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. had better</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had better\" (nên làm ngay bây giờ) là lời khuyên, không diễn tả một sự việc CẦN THIẾT ĐÃ XẢY RA trong quá khứ như câu yêu cầu.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. had to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Sự việc xảy ra trong quá khứ (\"broke down yesterday\") dẫn đến một sự CẦN THIẾT thực tế cũng ở quá khứ → had to (quá khứ của have to).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. has to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has to\" chia sai ngôi (dùng cho ngôi thứ ba số ít \"he/she/it\", không phải \"I\"), và cũng không đúng thì quá khứ.</span></div>"}, {"id": 12, "type": "fill", "q": "You__________tell anyone what I've revealed to you. It's still a secret.", "vi": "Bạn không được nói cho ai biết những gì tôi đã tiết lộ với bạn. Đó vẫn còn là bí mật.", "opts": ["A. mustn't", "B. had better not", "C. ought not to", "D. don't have to"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. mustn't</div><div class=\"ex-card mb-2\">You<b>mustn't</b>tell anyone what I've revealed to you. It's still a secret.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bạn không được nói cho ai biết những gì tôi đã tiết lộ với bạn. Đó vẫn còn là bí mật.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. mustn't</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"It's still a secret\" (vẫn là bí mật) nhấn mạnh sự CẤM ĐOÁN tuyệt đối, không được để lộ ra → mustn't.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. had better not</b><br><span style=\"font-weight:400;font-size:13px\">Sai — về ngữ pháp \"had better not\" cũng là lời khuyên mạnh hợp lý, nhưng \"mustn't\" phù hợp và dứt khoát hơn khi nhấn mạnh tính bảo mật tuyệt đối của một bí mật.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. ought not to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"ought not to\" chỉ là lời khuyên (mức trung bình), không đủ mạnh để diễn tả sự CẤM ĐOÁN nghiêm ngặt cần thiết để giữ bí mật.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. don't have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"don't have to\" (không cần thiết, vẫn được phép) hoàn toàn trái ngược với ý nghĩa CẤM tuyệt đối của việc giữ bí mật.</span></div>"}, {"id": 13, "type": "fill", "q": "- “Are you coming to Jeff’s party?” - “I’m not sure. I________go to the concert instead.”", "vi": "- \"Bạn có đến bữa tiệc của Jeff không?\" - \"Tôi không chắc. Có lẽ tôi sẽ đi xem hòa nhạc thay vào đó.\"", "opts": ["A. must", "B. would", "C. should", "D. may"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. may</div><div class=\"ex-card mb-2\">- “Are you coming to Jeff’s party?” - “I’m not sure. I<b>may</b>go to the concert instead.”</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> - \"Bạn có đến bữa tiệc của Jeff không?\" - \"Tôi không chắc. Có lẽ tôi sẽ đi xem hòa nhạc thay vào đó.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 7 — MAY vs MIGHT (có lẽ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must\" (chắc chắn phải) trái với thái độ KHÔNG CHẮC CHẮN (\"I'm not sure\") của người nói.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. would</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"would\" thường dùng cho câu điều kiện hoặc thói quen quá khứ, không phù hợp diễn tả khả năng ở đây.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should\" (nên) là lời khuyên/nghĩa vụ, không phù hợp với việc diễn tả một KHẢ NĂNG chưa chắc chắn.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. may</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"I'm not sure\" (không chắc) phù hợp với \"may\" — diễn tả một khả năng có thể xảy ra nhưng chưa chắc chắn.</span></div>"}, {"id": 14, "type": "fill", "q": "There was a lot of fun at yesterday’s party. You______come, but why didn’t you?", "vi": "Bữa tiệc hôm qua rất vui. Đáng lẽ bạn nên đến, nhưng sao bạn lại không đến vậy?", "opts": ["A. must have", "B. should", "C. need have", "D. should have"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. should have</div><div class=\"ex-card mb-2\">There was a lot of fun at yesterday’s party. You<b>should have</b>come, but why didn’t you?</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bữa tiệc hôm qua rất vui. Đáng lẽ bạn nên đến, nhưng sao bạn lại không đến vậy?</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must have</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must have\" (đã chắc chắn) không phù hợp — câu hỏi \"why didn't you?\" cho thấy người đó ĐÃ KHÔNG đến, cần diễn tả sự tiếc nuối, không phải suy đoán.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should\" (hiện tại/tương lai, không hoàn thành) không đúng — câu nói về một việc trong QUÁ KHỨ (bữa tiệc hôm qua) mà đã không xảy ra.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. need have</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"need have\" không phải cấu trúc chuẩn (thường dùng \"needn't have\" ở dạng phủ định); đây cũng không đúng cấu trúc modal perfect cho ngữ cảnh hối tiếc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. should have</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Bữa tiệc đã diễn ra (quá khứ) và người đó đã KHÔNG đến dù đáng lẽ nên đến → should have come (thể hiện qua \"should have\", với \"come\" được lược bỏ do đã nhắc ở câu trước).</span></div>"}, {"id": 15, "type": "fill", "q": "You__________17 to get a driving license in the UK.", "vi": "Bạn phải đủ 17 tuổi để được cấp bằng lái xe ở Anh.", "opts": ["A. needn't be", "B. should be", "C. have to be", "D. ought to be"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. have to be</div><div class=\"ex-card mb-2\">You<b>have to be</b>17 to get a driving license in the UK.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bạn phải đủ 17 tuổi để được cấp bằng lái xe ở Anh.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 2 — MUST vs HAVE TO (sự cần thiết chủ quan/khách quan)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. needn't be</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needn't be\" (không cần phải là) trái ngược hoàn toàn với yêu cầu bắt buộc về độ tuổi để được cấp bằng lái.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. should be</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should be\" (nên là) chỉ là gợi ý, không đủ mạnh để diễn tả một QUY ĐỊNH pháp lý bắt buộc về độ tuổi.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. have to be</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Đây là một QUY ĐỊNH khách quan của pháp luật (yêu cầu về độ tuổi tối thiểu) → have to be, phù hợp với bản chất khách quan, bên ngoài của quy định pháp luật.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. ought to be</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"ought to be\" cũng chỉ là lời khuyên (mức trung bình), không đủ mạnh để diễn tả một quy định pháp lý bắt buộc.</span></div>"}, {"id": 16, "type": "fill", "q": "The fire spread through the hotel very quickly but everyone_________ get out.", "vi": "Đám cháy lan nhanh khắp khách sạn nhưng mọi người đều đã kịp thoát ra ngoài.", "opts": ["A. had to", "B. would", "C. could", "D. was able to"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. was able to</div><div class=\"ex-card mb-2\">The fire spread through the hotel very quickly but everyone<b>was able to</b>_ get out.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Đám cháy lan nhanh khắp khách sạn nhưng mọi người đều đã kịp thoát ra ngoài.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 8 — CAN vs COULD</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. had to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had to\" (đã phải, buộc phải) diễn tả sự CẦN THIẾT, không phải KHẢ NĂNG thoát ra được.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. would</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"would\" thường dùng cho thói quen quá khứ hoặc câu điều kiện, không phù hợp để diễn tả một thành tích cụ thể đã đạt được.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. could</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"could\" (khả năng chung chung trong quá khứ) không phù hợp khi nói về một THÀNH TÍCH CỤ THỂ, đã thực sự đạt được trong một tình huống nguy hiểm cụ thể (theo quy tắc CAN/COULD).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. was able to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Đây là một THÀNH TÍCH CỤ THỂ đã đạt được (managed to) trong một tình huống nguy hiểm cụ thể (đám cháy) → was able to (không dùng \"could\" cho thành tích một lần cụ thể).</span></div>"}, {"id": 17, "type": "fill", "q": "Johnny, you__________play with the knife, you__________hurt yourself.", "vi": "Johnny, con không được chơi với con dao, con có thể sẽ tự làm mình bị thương đấy.", "opts": ["A. won’t/can’t", "B. mustn’t/may", "C. shouldn’t/must", "D. can’t/shouldn’t"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. mustn’t/may</div><div class=\"ex-card mb-2\">Johnny, you<b>mustn’t/may</b>play with the knife, you__________hurt yourself.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Johnny, con không được chơi với con dao, con có thể sẽ tự làm mình bị thương đấy.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. won’t/can’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"won't\" (sẽ không) không diễn tả được ý CẤM ĐOÁN cần thiết khi nói với trẻ con về việc nguy hiểm.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. mustn’t/may</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Mustn't\" (không được phép — cấm đoán, phù hợp cảnh báo trẻ con về nguy hiểm) + \"may\" (có thể xảy ra hậu quả, một khả năng) → mustn't play / may hurt.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. shouldn’t/must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"shouldn't\" (không nên, mức nhẹ) không đủ mạnh để cấm một hành động NGUY HIỂM (chơi dao); \"must\" ở vế sau cũng không phù hợp để diễn tả một khả năng không chắc chắn.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. can’t/shouldn’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can't\" ở vế đầu không diễn tả rõ sự CẤM ĐOÁN cần thiết; \"shouldn't\" ở vế sau (mức nhẹ) không phù hợp bằng \"may\" khi nói về hậu quả CÓ THỂ xảy ra.</span></div>"}, {"id": 18, "type": "fill", "q": "“Mary looks sad. Did you tell her about the accident?” - “Yes, but I______________________________her.”", "vi": "\"Mary trông có vẻ buồn. Bạn đã kể cho cô ấy về vụ tai nạn chưa?\" - \"Rồi, nhưng lẽ ra tôi không nên kể cho cô ấy.\"", "opts": ["A. shouldn't have told", "B. mustn't have told", "C. must have told", "D. should have told"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. shouldn't have told</div><div class=\"ex-card mb-2\">“Mary looks sad. Did you tell her about the accident?” - “Yes, but I<b>shouldn't have told</b>______her.”</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> \"Mary trông có vẻ buồn. Bạn đã kể cho cô ấy về vụ tai nạn chưa?\" - \"Rồi, nhưng lẽ ra tôi không nên kể cho cô ấy.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. shouldn't have told</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Việc đã kể (khiến Mary buồn) là điều LẼ RA không nên làm nhưng đã làm rồi → shouldn't have told (hối tiếc về việc đã làm).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. mustn't have told</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't have told\" không phải là cấu trúc modal perfect chuẩn.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. must have told</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must have told\" là suy đoán rằng việc kể CHẮC CHẮN đã xảy ra, nhưng thực tế người nói đã XÁC NHẬN rồi (\"Yes\") nên không cần suy đoán nữa; hơn nữa không mang ý hối tiếc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. should have told</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should have told\" (lẽ ra nên kể) trái ngược hoàn toàn với ngữ cảnh hối tiếc vì ĐÃ kể khiến Mary buồn.</span></div>"}, {"id": 19, "type": "fill", "q": "- “Shall I tell John about it?” - “No, you__________. I’ve told him already.”", "vi": "- \"Để tôi kể cho John nghe về việc đó nhé?\" - \"Không cần đâu. Tôi đã kể cho anh ấy rồi.\"", "opts": ["A. needn’t", "B. wouldn’t", "C. mustn’t", "D. shouldn’t"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. needn’t</div><div class=\"ex-card mb-2\">- “Shall I tell John about it?” - “No, you<b>needn’t</b>. I’ve told him already.”</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> - \"Để tôi kể cho John nghe về việc đó nhé?\" - \"Không cần đâu. Tôi đã kể cho anh ấy rồi.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. needn’t</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"I've told him already\" (đã kể rồi) khiến việc kể lại trở nên KHÔNG CẦN THIẾT → needn't (không cần thiết, vẫn được phép nếu muốn).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. wouldn’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"wouldn't\" (sẽ không) không phù hợp ngữ pháp/ngữ nghĩa để trả lời cho câu đề nghị \"Shall I...?\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. mustn’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't\" (không được phép) mang nghĩa CẤM ĐOÁN, không đúng — không có gì SAI khi kể lại, chỉ là không CẦN THIẾT.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. shouldn’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"shouldn't\" (không nên) là lời khuyên phản đối, không phù hợp bằng \"needn't\" khi lý do chỉ đơn giản là việc đó đã được làm rồi (không còn cần thiết).</span></div>"}, {"id": 20, "type": "fill", "q": "- “Don’t forget to come to my birthday party tomorrow.” -“__________.”", "vi": "- \"Đừng quên đến dự tiệc sinh nhật của tớ vào ngày mai nhé.\" - \"Tớ sẽ không quên đâu.\"", "opts": ["A. I don’t", "B. I won’t", "C. I can’t", "D. I haven’t"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. I won’t</div><div class=\"ex-card mb-2\">- “Don’t forget to come to my birthday party tomorrow.” -“<b>I won’t</b>.”</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> - \"Đừng quên đến dự tiệc sinh nhật của tớ vào ngày mai nhé.\" - \"Tớ sẽ không quên đâu.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 6 — SHALL vs WILL</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. I don’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"I don't\" (thì hiện tại đơn) không phù hợp để trả lời một lời NHẮC NHỞ về việc trong tương lai.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. I won’t</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"I won't (forget)\" là cách trả lời tự nhiên cho lời nhắc \"Don't forget\", nghĩa là \"Tôi sẽ không (quên) đâu\" — một lời hứa/cam kết cho tương lai.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. I can’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"I can't\" (tôi không thể) không hợp lý — không liên quan đến khả năng, mà là một lời HỨA không quên.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. I haven’t</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"I haven't\" (thì hiện tại hoàn thành) không phù hợp ngữ pháp/ngữ cảnh khi trả lời cho một lời nhắc về tương lai.</span></div>"}, {"id": 21, "type": "fill", "q": "You__________type these documents now. It’s not urgent.", "vi": "Bạn không cần gõ những tài liệu này ngay bây giờ đâu. Nó không gấp.", "opts": ["A. can't", "B. needn’t", "C. mustn't", "D. may not"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. needn’t</div><div class=\"ex-card mb-2\">You<b>needn’t</b>type these documents now. It’s not urgent.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bạn không cần gõ những tài liệu này ngay bây giờ đâu. Nó không gấp.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. can't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can't\" (không thể) không phù hợp — không phải là vấn đề về khả năng, mà là về sự CẦN THIẾT.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. needn’t</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"It's not urgent\" (không gấp) → việc gõ tài liệu ngay bây giờ là KHÔNG CẦN THIẾT: needn't.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. mustn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't\" (không được phép — cấm đoán) sai hoàn toàn nghĩa; không có gì cấm việc gõ tài liệu, chỉ là không cần vội.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. may not</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"may not\" (có thể sẽ không / không được phép) không diễn tả đúng ý \"không cần thiết\" mà câu muốn truyền đạt.</span></div>"}, {"id": 22, "type": "fill", "q": "Peter__________come with us tonight, but I’m not sure.", "vi": "Có lẽ Peter sẽ đi cùng chúng ta tối nay, nhưng tôi không chắc.", "opts": ["A. must", "B. may", "C. can", "D. will"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. may</div><div class=\"ex-card mb-2\">Peter<b>may</b>come with us tonight, but I’m not sure.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Có lẽ Peter sẽ đi cùng chúng ta tối nay, nhưng tôi không chắc.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 7 — MAY vs MIGHT (có lẽ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must\" (chắc chắn) trái với thái độ không chắc chắn (\"I'm not sure\") của người nói.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. may</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"I'm not sure\" (không chắc) phù hợp với \"may\" — diễn tả khả năng có thể xảy ra nhưng chưa chắc chắn.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. can</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can\" diễn tả khả năng chung/năng lực, không phù hợp để diễn tả một khả năng KHÔNG CHẮC CHẮN về việc sẽ xảy ra hay không.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. will</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"will\" diễn tả sự chắc chắn/dự đoán mạnh, không phù hợp với thái độ không chắc chắn thể hiện qua \"I'm not sure\".</span></div>"}, {"id": 23, "type": "fill", "q": "You__________touch electrical wires with wet hands.", "vi": "Bạn không được chạm vào dây điện khi tay ướt.", "opts": ["A. needn't", "B. mustn't", "C. don't have to", "D. aren't allowed to"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. mustn't</div><div class=\"ex-card mb-2\">You<b>mustn't</b>touch electrical wires with wet hands.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bạn không được chạm vào dây điện khi tay ướt.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. needn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needn't\" (không cần thiết, vẫn được phép nếu muốn) không phù hợp với một cảnh báo về sự NGUY HIỂM cần cấm tuyệt đối.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. mustn't</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Đây là một cảnh báo AN TOÀN quan trọng (nguy hiểm chết người) → mustn't (cấm đoán tuyệt đối).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. don't have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"don't have to\" (không cần thiết) không mang ý cấm đoán như ngữ cảnh nguy hiểm yêu cầu.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. aren't allowed to</b><br><span style=\"font-weight:400;font-size:13px\">Sai — về nghĩa \"aren't allowed to\" cũng gần đúng (không được phép), nhưng \"mustn't\" là từ được dùng phổ biến và trực tiếp hơn để diễn tả lời CẢNH BÁO AN TOÀN mạnh mẽ, khẩn cấp như trong câu này.</span></div>"}, {"id": 24, "type": "fill", "q": "We__________last night, but we went to the concert instead.", "vi": "Lẽ ra tối qua chúng tôi nên học bài, nhưng chúng tôi lại đi xem hòa nhạc.", "opts": ["A. must have studied", "B. might study", "C. should have studied", "D. would study"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. should have studied</div><div class=\"ex-card mb-2\">We<b>should have studied</b>last night, but we went to the concert instead.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Lẽ ra tối qua chúng tôi nên học bài, nhưng chúng tôi lại đi xem hòa nhạc.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must have studied</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must have studied\" là suy đoán rằng việc học CHẮC CHẮN đã xảy ra, nhưng câu sau (\"went to the concert instead\") cho thấy họ đã KHÔNG học.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. might study</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"might study\" (hiện tại/tương lai) không khớp thì với \"last night\" (quá khứ).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. should have studied</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Việc học bài là điều LẼ RA nên làm nhưng đã không làm (đi xem hòa nhạc thay vào đó) → should have studied (hối tiếc về quá khứ).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. would study</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"would study\" không phải cấu trúc phù hợp để diễn tả sự hối tiếc về một việc lẽ ra nên làm trong quá khứ.</span></div>"}, {"id": 25, "type": "fill", "q": "\"Nancy brought some food for the party.\" \"She_________, we have plenty.\"", "vi": "\"Nancy đã mang đồ ăn đến bữa tiệc.\" \"Cô ấy không cần làm vậy đâu, chúng ta có nhiều rồi.\"", "opts": ["A. needn't", "B. doesn't have to", "C. didn't need to", "D. needn't have brought"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. needn't have brought</div><div class=\"ex-card mb-2\">\"Nancy brought some food for the party.\" \"She<b>needn't have brought</b>_, we have plenty.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> \"Nancy đã mang đồ ăn đến bữa tiệc.\" \"Cô ấy không cần làm vậy đâu, chúng ta có nhiều rồi.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. needn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needn't\" (hiện tại, chưa hoàn thành) không phù hợp — Nancy ĐÃ mang đồ ăn rồi (quá khứ, hành động đã hoàn tất), cần cấu trúc modal perfect.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. doesn't have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"doesn't have to\" (hiện tại đơn) cũng không khớp thì với việc Nancy ĐÃ MANG đồ ăn xong rồi.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. didn't need to</b><br><span style=\"font-weight:400;font-size:13px\">Sai — \"didn't need to\" (không cần làm và THỰC TẾ CŨNG KHÔNG LÀM) không chính xác bằng \"needn't have + Vp2\" trong trường hợp này, vì Nancy THỰC SỰ ĐÃ mang đồ ăn (một việc thừa nhưng đã làm), khác với việc \"không cần và không làm\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. needn't have brought</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Nancy ĐÃ mang đồ ăn (một việc thừa, không cần thiết nhưng đã làm rồi) → needn't have brought (lẽ ra không cần thiết phải làm nhưng đã làm).</span></div>"}, {"id": 26, "type": "fill", "q": "I didn't hear the phone. I__________asleep.", "vi": "Tôi đã không nghe thấy điện thoại reo. Chắc là tôi đã ngủ say rồi.", "opts": ["A. must be", "B. must have been", "C. should be", "D. should have been"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. must have been</div><div class=\"ex-card mb-2\">I didn't hear the phone. I<b>must have been</b>asleep.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tôi đã không nghe thấy điện thoại reo. Chắc là tôi đã ngủ say rồi.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must be</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must be\" (hiện tại) không khớp thì với ngữ cảnh hoàn toàn ở QUÁ KHỨ (\"didn't hear\").</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. must have been</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Có bằng chứng rõ ràng (không nghe thấy điện thoại) để suy đoán chắc chắn về một trạng thái đã xảy ra trong quá khứ → must have been (chắc hẳn là đã...).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. should be</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should be\" (nên là, hiện tại) không phù hợp cả về thì lẫn ý nghĩa (đây là suy đoán, không phải lời khuyên).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. should have been</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should have been\" mang ý nghĩa HỐI TIẾC (lẽ ra nên...) chứ không phải suy đoán về nguyên nhân, không phù hợp ngữ cảnh này.</span></div>"}, {"id": 27, "type": "fill", "q": "What Jim says__________true but I very much doubt it.", "vi": "Điều Jim nói có thể đúng nhưng tôi rất nghi ngờ điều đó.", "opts": ["A. should be", "B. will be", "C. must be", "D. may be"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. may be</div><div class=\"ex-card mb-2\">What Jim says<b>may be</b>true but I very much doubt it.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Điều Jim nói có thể đúng nhưng tôi rất nghi ngờ điều đó.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 7 — MAY vs MIGHT (có lẽ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. should be</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should be\" (lẽ ra nên là/có lẽ đúng theo logic) không phù hợp với thái độ NGHI NGỜ mạnh (\"I very much doubt it\") của người nói.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. will be</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"will be\" (sẽ, dự đoán chắc chắn) trái với thái độ nghi ngờ, không chắc chắn của người nói.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. must be</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must be\" (chắc chắn là) quá mạnh, mâu thuẫn với việc người nói RẤT NGHI NGỜ điều đó.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. may be</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"May be\" (có thể đúng) phù hợp với thái độ vừa thừa nhận khả năng đúng, vừa nghi ngờ mạnh mẽ (but I doubt it) của người nói.</span></div>"}, {"id": 28, "type": "fill", "q": "There was plenty of time. She__________.", "vi": "Có rất nhiều thời gian mà. Đáng lẽ cô ấy không cần phải vội vàng như vậy.", "opts": ["A. mustn't have hurried", "B. couldn't have hurried", "C. must not hurry", "D. needn't have hurried"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. needn't have hurried</div><div class=\"ex-card mb-2\">There was plenty of time. She<b>needn't have hurried</b>.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Có rất nhiều thời gian mà. Đáng lẽ cô ấy không cần phải vội vàng như vậy.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. mustn't have hurried</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't have hurried\" không phải là cấu trúc modal perfect chuẩn trong tiếng Anh.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. couldn't have hurried</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"couldn't have hurried\" (không thể đã vội) mang nghĩa phủ định khả năng đã xảy ra, không phù hợp — thực tế cô ấy CÓ vội, chỉ là không cần thiết.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. must not hurry</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must not hurry\" (hiện tại, cấm đoán) không khớp thì và không đúng ý nghĩa — đây không phải lệnh cấm mà là nhận xét về sự thừa thãi của hành động ĐÃ xảy ra.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. needn't have hurried</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"There was plenty of time\" (có nhiều thời gian) cho thấy việc vội vàng là THỪA, không cần thiết nhưng cô ấy đã làm → needn't have hurried.</span></div>"}, {"id": 29, "type": "fill", "q": "- “Must we do it now?” –“No, you__________.”", "vi": "- \"Chúng tôi có phải làm việc đó ngay bây giờ không?\" - \"Không, bạn không cần đâu.\"", "opts": ["A. won't", "B. needn't", "C. can't", "D. don't"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. needn't</div><div class=\"ex-card mb-2\">- “Must we do it now?” –“No, you<b>needn't</b>.”</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> - \"Chúng tôi có phải làm việc đó ngay bây giờ không?\" - \"Không, bạn không cần đâu.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. won't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"won't\" (sẽ không) không phải câu trả lời phù hợp cho câu hỏi về sự CẦN THIẾT (\"Must we...?\").</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. needn't</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Trả lời phủ định cho câu hỏi \"Must...?\" (Có phải...không?) thường dùng \"needn't\" (không cần thiết) chứ không dùng \"mustn't\" (vì mustn't lại mang nghĩa cấm đoán, khác hẳn ý phủ định của \"must\").</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. can't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can't\" (không thể) không phù hợp để trả lời câu hỏi về sự bắt buộc/cần thiết.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. don't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"don't\" một mình không tạo thành câu trả lời hoàn chỉnh, có ý nghĩa cho câu hỏi dùng động từ khuyết thiếu \"must\".</span></div>"}, {"id": 30, "type": "fill", "q": "-Hurry up! Tom__________for us at the school gate.", "vi": "Nhanh lên! Chắc là Tom đang đợi chúng ta ở cổng trường đấy.", "opts": ["A. must wait", "B. must be waiting", "C. must be waited", "D. must have been waited"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. must be waiting</div><div class=\"ex-card mb-2\">-Hurry up! Tom<b>must be waiting</b>for us at the school gate.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Nhanh lên! Chắc là Tom đang đợi chúng ta ở cổng trường đấy.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must wait</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must wait\" (phải đợi — mang nghĩa BẮT BUỘC Tom phải đợi) không đúng ý nghĩa cần thiết ở đây, vốn là một sự SUY ĐOÁN về việc Tom ĐANG đợi (không phải ra lệnh cho Tom).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. must be waiting</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Suy đoán về một hành động ĐANG diễn ra ở hiện tại (Tom hẳn đang đợi) → must be + V-ing (modal + tiếp diễn).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. must be waited</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng bị động, trong khi \"Tom\" là người TỰ đợi (chủ động), không phải bị ai đợi.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. must have been waited</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc bị động hoàn thành không phù hợp cả về nghĩa (Tom tự đợi, chủ động) lẫn ngữ pháp phức tạp không cần thiết ở đây.</span></div>"}, {"id": 31, "type": "fill", "q": "- \"I think Jane is at home.\" - \"No, she__________be at home, for she phoned me from the airport just ten minutes ago.\"", "vi": "- \"Tôi nghĩ Jane đang ở nhà.\" - \"Không, cô ấy không thể ở nhà được, vì cô ấy vừa gọi điện cho tôi từ sân bay mười phút trước.\"", "opts": ["A. mustn't", "B. needn't", "C. can't", "D. daren't"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. can't</div><div class=\"ex-card mb-2\">- \"I think Jane is at home.\" - \"No, she<b>can't</b>be at home, for she phoned me from the airport just ten minutes ago.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> - \"Tôi nghĩ Jane đang ở nhà.\" - \"Không, cô ấy không thể ở nhà được, vì cô ấy vừa gọi điện cho tôi từ sân bay mười phút trước.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. mustn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't\" (không được phép) không phải cấu trúc dùng để PHỦ ĐỊNH một suy đoán/khả năng.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. needn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needn't\" (không cần thiết) không liên quan đến việc phủ định khả năng cô ấy đang ở nhà.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. can't</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Có bằng chứng rõ ràng (vừa gọi từ sân bay) để PHỦ ĐỊNH khả năng cô ấy đang ở nhà → can't be (không thể đang...).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. daren't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"daren't\" (không dám) hoàn toàn không liên quan đến ngữ cảnh suy đoán/phủ định khả năng này.</span></div>"}, {"id": 32, "type": "fill", "q": "He__________have committed the crime because he was with me on that day.", "vi": "Anh ta không thể nào đã phạm tội vì anh ta đã ở cùng tôi vào ngày hôm đó.", "opts": ["A. mustn't", "B. shouldn't", "C. won't", "D. can’t"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. can’t</div><div class=\"ex-card mb-2\">He<b>can’t</b>have committed the crime because he was with me on that day.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Anh ta không thể nào đã phạm tội vì anh ta đã ở cùng tôi vào ngày hôm đó.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. mustn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"mustn't have committed\" không phải cấu trúc modal perfect chuẩn.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. shouldn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"shouldn't have committed\" mang ý nghĩa PHÊ PHÁN việc đã phạm tội (hối tiếc), không phù hợp với ý PHỦ ĐỊNH hoàn toàn khả năng anh ta đã phạm tội.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. won't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"won't have committed\" không phải cấu trúc modal perfect tồn tại (won't không kết hợp theo cách này để chỉ suy đoán quá khứ).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. can’t</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Có bằng chứng ngoại phạm rõ ràng (ở cùng người nói) để PHỦ ĐỊNH khả năng phạm tội → can't have committed (không thể nào đã...).</span></div>"}, {"id": 33, "type": "fill", "q": "Since we have to be there by 8.30, we__________take a taxi.", "vi": "Vì chúng ta phải có mặt ở đó trước 8 giờ 30, chúng ta nên bắt taxi thôi.", "opts": ["A. have to", "B. may", "C. ought to", "D. are able to"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. ought to</div><div class=\"ex-card mb-2\">Since we have to be there by 8.30, we<b>ought to</b>take a taxi.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Vì chúng ta phải có mặt ở đó trước 8 giờ 30, chúng ta nên bắt taxi thôi.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 5 — SHOULD vs OUGHT TO (lời khuyên)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. have to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have to\" đã được dùng ở vế trước (have to be there); dùng lại \"have to\" ở vế sau nghe không tự nhiên bằng một gợi ý hợp lý cho GIẢI PHÁP để đạt được điều đó.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. may</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"may\" (có thể) chỉ diễn tả khả năng, không phù hợp với việc đưa ra một GIẢI PHÁP/gợi ý hợp lý để giải quyết vấn đề thời gian.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. ought to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Ought to\" (nên) phù hợp để đưa ra một GỢI Ý/giải pháp hợp lý (bắt taxi) nhằm đáp ứng yêu cầu về thời gian đã nêu ở vế trước.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. are able to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"are able to\" (có khả năng) không phù hợp — đây không phải vấn đề về khả năng bắt taxi, mà là một GỢI Ý nên làm gì.</span></div>"}, {"id": 34, "type": "fill", "q": "She hasn't eaten anything since yesterday. She__________be really hungry now.", "vi": "Cô ấy chưa ăn gì từ hôm qua đến giờ. Chắc chắn bây giờ cô ấy đang rất đói.", "opts": ["A. might", "B. will", "C. must", "D. can"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. must</div><div class=\"ex-card mb-2\">She hasn't eaten anything since yesterday. She<b>must</b>be really hungry now.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Cô ấy chưa ăn gì từ hôm qua đến giờ. Chắc chắn bây giờ cô ấy đang rất đói.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. might</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"might\" diễn tả khả năng không chắc chắn, trong khi có bằng chứng RÕ RÀNG (chưa ăn gì từ hôm qua) để suy đoán chắc chắn hơn.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. will</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"will\" diễn tả dự đoán/thói quen tương lai, không phù hợp với việc SUY ĐOÁN dựa trên bằng chứng có sẵn ở hiện tại.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. must</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Có bằng chứng rõ ràng (chưa ăn gì từ hôm qua) để suy đoán chắc chắn về trạng thái hiện tại → must be (chắc chắn là).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. can</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can\" diễn tả khả năng/năng lực chung, không phù hợp để diễn tả một SUY ĐOÁN chắc chắn dựa trên bằng chứng cụ thể.</span></div>"}, {"id": 35, "type": "fill", "q": "I put my keys on the table, but now it's gone. Someone__________have taken it.", "vi": "Tôi để chìa khóa trên bàn, nhưng giờ nó biến mất rồi. Chắc là ai đó đã lấy nó.", "opts": ["A. may", "B. had to", "C. should", "D. would rather"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. may</div><div class=\"ex-card mb-2\">I put my keys on the table, but now it's gone. Someone<b>may</b>have taken it.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tôi để chìa khóa trên bàn, nhưng giờ nó biến mất rồi. Chắc là ai đó đã lấy nó.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. may</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Đây là một suy đoán KHÔNG CHẮC CHẮN về nguyên nhân chìa khóa biến mất → may have taken (có thể đã lấy).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. had to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had to have taken\" không phải cấu trúc tồn tại (had to không kết hợp theo cách này với have+Vp2 để chỉ suy đoán).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should have taken\" mang ý nghĩa HỐI TIẾC/phê phán (lẽ ra nên lấy), hoàn toàn không phù hợp với việc suy đoán ai đó đã lấy trộm chìa khóa.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. would rather</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"would rather have taken\" (thà đã lấy) không liên quan đến việc suy đoán nguyên nhân của sự việc.</span></div>"}, {"id": 36, "type": "fill", "q": "Daisy has a test tomorrow, so she__________be studying.", "vi": "Daisy có bài kiểm tra vào ngày mai, nên chắc là cô ấy đang học bài.", "opts": ["A. will", "B. should", "C. must", "D. can"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. must</div><div class=\"ex-card mb-2\">Daisy has a test tomorrow, so she<b>must</b>be studying.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Daisy có bài kiểm tra vào ngày mai, nên chắc là cô ấy đang học bài.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. will</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"will be studying\" (dự đoán tương lai đơn thuần) không nhấn mạnh được tính LOGIC, chắc chắn của suy đoán dựa trên hoàn cảnh (có bài kiểm tra ngày mai).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. should</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"should be studying\" mang ý mong đợi/khuyên nhủ (cô ấy nên đang học), nhẹ hơn một suy đoán chắc chắn dựa trên logic hoàn cảnh.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. must</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Từ hoàn cảnh logic (có bài kiểm tra ngày mai) suy đoán chắc chắn về hành động đang diễn ra ở hiện tại → must be studying.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. can</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can be studying\" không phải cấu trúc tự nhiên để diễn tả suy đoán logic về một hành động đang diễn ra.</span></div>"}, {"id": 37, "type": "fill", "q": "Tom painted his room black. It looks dark and dreary. He__________have chosen another color.", "vi": "Tom đã sơn phòng của mình màu đen. Nó trông tối tăm và ảm đạm. Đáng lẽ anh ấy nên chọn màu khác.", "opts": ["A. should", "B. must", "C. could", "D. may"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. should</div><div class=\"ex-card mb-2\">Tom painted his room black. It looks dark and dreary. He<b>should</b>have chosen another color.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tom đã sơn phòng của mình màu đen. Nó trông tối tăm và ảm đạm. Đáng lẽ anh ấy nên chọn màu khác.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. should</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Đây là một lời PHÊ PHÁN/nhận xét rằng Tom lẽ ra nên chọn màu khác (nhưng đã không làm) → should have chosen (hối tiếc/phê bình về quyết định trong quá khứ).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. must</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must have chosen\" là suy đoán rằng việc chọn màu khác CHẮC CHẮN đã xảy ra, nhưng thực tế Tom đã chọn màu ĐEN (trái với giả định này).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. could</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"could have chosen\" chỉ nêu khả năng đã có thể chọn màu khác, không mang tính PHÊ PHÁN rõ ràng như \"should have\" trong ngữ cảnh chê bai quyết định của Tom.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. may</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"may have chosen\" là suy đoán không chắc chắn, không phù hợp với việc đưa ra ý kiến/lời phê bình rõ ràng về quyết định sai lầm của Tom.</span></div>"}, {"id": 38, "type": "fill", "q": "You__________throw litter on the streets.", "vi": "Bạn không được vứt rác trên đường phố.", "opts": ["A. mustn't", "B. couldn't", "C. needn't", "D. won't"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. mustn't</div><div class=\"ex-card mb-2\">You<b>mustn't</b>throw litter on the streets.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bạn không được vứt rác trên đường phố.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 4 — MUSTN'T vs NEEDN'T (cấm đoán / không cần thiết)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. mustn't</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Đây là một quy tắc/hành vi bị CẤM (vứt rác nơi công cộng) → mustn't (không được phép).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. couldn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"couldn't\" (không thể) diễn tả sự bất khả về khả năng, không phù hợp với ý CẤM ĐOÁN hành vi.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. needn't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needn't\" (không cần thiết, vẫn được phép nếu muốn) không đúng ý nghĩa — đây là một điều CẤM, không phải chỉ là không cần thiết.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. won't</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"won't\" (sẽ không) không phải là modal diễn tả sự cấm đoán về quy tắc ứng xử.</span></div>"}, {"id": 39, "type": "fill", "q": "\"Did you do all the tasks yesterday?\" - \"No, I__________it, but I spent too much time doing the first task.\"", "vi": "\"Hôm qua bạn đã làm hết các nhiệm vụ chưa?\" - \"Chưa, lẽ ra tôi đã có thể làm được, nhưng tôi tốn quá nhiều thời gian cho nhiệm vụ đầu tiên.\"", "opts": ["A. must have done", "B. could have done", "C. needn't do", "D. shouldn't have done"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. could have done</div><div class=\"ex-card mb-2\">\"Did you do all the tasks yesterday?\" - \"No, I<b>could have done</b>it, but I spent too much time doing the first task.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> \"Hôm qua bạn đã làm hết các nhiệm vụ chưa?\" - \"Chưa, lẽ ra tôi đã có thể làm được, nhưng tôi tốn quá nhiều thời gian cho nhiệm vụ đầu tiên.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must have done</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must have done\" là suy đoán rằng việc đó CHẮC CHẮN đã xảy ra, nhưng câu trả lời \"No\" cho thấy công việc đã KHÔNG được hoàn thành.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. could have done</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Could have done\" diễn tả rằng người nói CÓ KHẢ NĂNG đã hoàn thành công việc (nếu không mất quá nhiều thời gian cho việc đầu), nhưng thực tế đã KHÔNG hoàn thành — đúng với ý nghĩa \"có lẽ đã có thể nhưng thực tế không\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. needn't do</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"needn't do\" (hiện tại, không hoàn thành) không khớp thì và ý nghĩa với ngữ cảnh nói về một việc đã KHÔNG hoàn thành trong quá khứ do thiếu thời gian.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. shouldn't have done</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"shouldn't have done\" mang ý PHÊ PHÁN việc đã làm (lẽ ra không nên làm), hoàn toàn trái với ngữ cảnh đang giải thích lý do CHƯA hoàn thành công việc.</span></div>"}, {"id": 40, "type": "fill", "q": "My supervisor is angry with me. I didn’t do all the work I__________ last week.", "vi": "Người giám sát của tôi đang tức giận với tôi. Tôi đã không hoàn thành hết công việc mà lẽ ra tôi nên làm tuần trước.", "opts": ["A. must have done", "B. may have done", "C. should have done", "D. need to have done"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. should have done</div><div class=\"ex-card mb-2\">My supervisor is angry with me. I didn’t do all the work I<b>should have done</b> last week.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Người giám sát của tôi đang tức giận với tôi. Tôi đã không hoàn thành hết công việc mà lẽ ra tôi nên làm tuần trước.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Mục 9 — MODAL + HAVE + Vp2 (suy đoán/đánh giá về quá khứ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must have done</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"must have done\" là suy đoán rằng việc đó CHẮC CHẮN đã xảy ra, trái với thực tế đã nêu rõ (\"didn't do all the work\").</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. may have done</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"may have done\" diễn tả khả năng không chắc chắn, không phù hợp với việc khẳng định rõ ràng có một NGHĨA VỤ đã không được hoàn thành.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. should have done</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Công việc là điều LẼ RA phải hoàn thành (nghĩa vụ) nhưng đã không làm, dẫn đến việc sếp tức giận → should have done (thể hiện nghĩa vụ chưa hoàn thành).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. need to have done</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"need to have done\" không phải cấu trúc chuẩn của modal perfect để diễn tả nghĩa vụ chưa hoàn thành trong quá khứ.</span></div>"}];
